        return N === 1 ? [0] : [];
    }

    // O[k]: Count of odd numbers in nums[k...N-1]
    const O = new Array(N + 1).fill(0);
    // E[k]: Count of even numbers in nums[k...N-1]
    const E = new Array(N + 1).fill(0);

    // Step 1: Calculate suffix counts (O(N))
    for (let k = N - 1; k >= 0; k--) {
        if (nums[k] % 2 !== 0) { // Odd
            O[k] = O[k + 1] + 1;
            E[k] = E[k + 1];
        } else { // Even
            E[k] = E[k + 1] + 1;
            O[k] = O[k + 1];
        }
    }

    const answer = new Array(N);

    // Step 2: Calculate scores for each index i (O(N))
    for (let i = 0; i < N; i++) {
        // We need the counts in the suffix starting from i + 1
        const suffixOddCount = O[i + 1];
        const suffixEvenCount = E[i + 1];

        if (nums[i] % 2 !== 0) { // nums[i] is Odd
            // Score is the count of even numbers to the right
            answer[i] = suffixEvenCount;
        } else { // nums[i] is Even
            // Score is the count of odd numbers to the right
            answer[i] = suffixOddCount;
        }
    }

    return answer;
}
